import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface WeeklyActivity {
  day: string;
  activity: number;
}

interface FitnessData {
  widget: {
    id: string;
    app: string;
    version: string;
  };
  data: {
    dailyStats: {
      steps: number;
      calories: number;
    };
    weeklyActivity: WeeklyActivity[];
  };
  meta: {
    theme: string;
    dataMode: string;
    layout: string;
    primaryColor: string;
    accentColor: string;
    chartTypes: string[];
  };
}

export default function Widget() {
  const fitnessData = response.data as FitnessData;
  const { dailyStats, weeklyActivity } = fitnessData.data;
  const { primaryColor, accentColor } = fitnessData.meta;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: primaryColor }}>
              Daily Fitness Tracker
            </Typography>
            <Typography variant="body1" color="text.secondary">
              Steps: {dailyStats.steps.toLocaleString()}
            </Typography>
            <Typography variant="body1" color="text.secondary">
              Calories: {dailyStats.calories}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: weeklyActivity.map(activity => activity.activity),
                  color: accentColor,
                  label: 'Activity (min)',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: weeklyActivity.map(activity => activity.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'activity' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="activity"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
